ALTER TABLE public.owners ADD COLUMN IF NOT EXISTS store_credit_cents integer NOT NULL DEFAULT 0; ALTER TABLE public.subscription_packages ADD COLUMN IF NOT EXISTS validity_days integer; ALTER TABLE public.subscription_packages ADD COLUMN IF NOT EXISTS service_type text; CREATE TABLE IF NOT EXISTS public.retail_products (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid NOT NULL, name text NOT NULL, sku text, category text NOT NULL DEFAULT 'other', description text, price_cents integer NOT NULL DEFAULT 0, cost_cents integer NOT NULL DEFAULT 0, stock_quantity integer NOT NULL DEFAULT 0, reorder_point integer NOT NULL DEFAULT 0, manufacturer text, vendor text, photo_url text, active boolean NOT NULL DEFAULT true, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), deleted_at timestamptz); ALTER TABLE public.retail_products ENABLE ROW LEVEL SECURITY; CREATE POLICY "Tenant isolation select" ON public.retail_products FOR SELECT USING (is_org_member(organization_id)); CREATE POLICY "Tenant isolation insert" ON public.retail_products FOR INSERT WITH CHECK (is_org_member(organization_id)); CREATE POLICY "Tenant isolation update" ON public.retail_products FOR UPDATE USING (is_org_member(organization_id)); CREATE POLICY "Tenant isolation delete" ON public.retail_products FOR DELETE USING (is_org_member(organization_id)); CREATE TRIGGER set_retail_products_updated_at BEFORE UPDATE ON public.retail_products FOR EACH ROW EXECUTE FUNCTION public.set_updated_at(); CREATE INDEX idx_retail_products_org ON public.retail_products(organization_id); CREATE UNIQUE INDEX idx_retail_products_sku_org ON public.retail_products(organization_id, lower(sku)) WHERE sku IS NOT NULL AND deleted_at IS NULL; CREATE TABLE IF NOT EXISTS public.promotions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid NOT NULL, code text NOT NULL, description text, discount_type text NOT NULL DEFAULT 'percent', discount_value integer NOT NULL DEFAULT 0, valid_from timestamptz, valid_to timestamptz, usage_count integer NOT NULL DEFAULT 0, max_uses integer, active boolean NOT NULL DEFAULT true, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), deleted_at timestamptz); ALTER TABLE public.promotions ENABLE ROW LEVEL SECURITY; CREATE POLICY "Tenant isolation select" ON public.promotions FOR SELECT USING (is_org_member(organization_id)); CREATE POLICY "Tenant isolation insert" ON public.promotions FOR INSERT WITH CHECK (is_org_member(organization_id)); CREATE POLICY "Tenant isolation update" ON public.promotions FOR UPDATE USING (is_org_member(organization_id)); CREATE POLICY "Tenant isolation delete" ON public.promotions FOR DELETE USING (is_org_member(organization_id)); CREATE TRIGGER set_promotions_updated_at BEFORE UPDATE ON public.promotions FOR EACH ROW EXECUTE FUNCTION public.set_updated_at(); CREATE UNIQUE INDEX idx_promotions_code_org ON public.promotions(organization_id, lower(code)) WHERE deleted_at IS NULL; CREATE TABLE IF NOT EXISTS public.pos_carts (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid NOT NULL, owner_id uuid NOT NULL, cashier_user_id uuid, status text NOT NULL DEFAULT 'open', notes text, promotion_id uuid, applied_store_credit_cents integer NOT NULL DEFAULT 0, subtotal_cents integer NOT NULL DEFAULT 0, discount_cents integer NOT NULL DEFAULT 0, tax_cents integer NOT NULL DEFAULT 0, total_cents integer NOT NULL DEFAULT 0, invoice_id uuid, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), charged_at timestamptz, voided_at timestamptz); ALTER TABLE public.pos_carts ENABLE ROW LEVEL SECURITY; CREATE POLICY "Tenant isolation select" ON public.pos_carts FOR SELECT USING (is_org_member(organization_id)); CREATE POLICY "Tenant isolation insert" ON public.pos_carts FOR INSERT WITH CHECK (is_org_member(organization_id)); CREATE POLICY "Tenant isolation update" ON public.pos_carts FOR UPDATE USING (is_org_member(organization_id)); CREATE POLICY "Tenant isolation delete" ON public.pos_carts FOR DELETE USING (is_org_member(organization_id)); CREATE TRIGGER set_pos_carts_updated_at BEFORE UPDATE ON public.pos_carts FOR EACH ROW EXECUTE FUNCTION public.set_updated_at(); CREATE INDEX idx_pos_carts_org_status ON public.pos_carts(organization_id, status); CREATE TABLE IF NOT EXISTS public.pos_cart_items (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid NOT NULL, cart_id uuid NOT NULL, item_kind text NOT NULL, service_id uuid, product_id uuid, package_id uuid, name text NOT NULL, quantity integer NOT NULL DEFAULT 1, unit_price_cents integer NOT NULL DEFAULT 0, line_total_cents integer NOT NULL DEFAULT 0, created_at timestamptz NOT NULL DEFAULT now()); ALTER TABLE public.pos_cart_items ENABLE ROW LEVEL SECURITY; CREATE POLICY "Tenant isolation select" ON public.pos_cart_items FOR SELECT USING (is_org_member(organization_id)); CREATE POLICY "Tenant isolation insert" ON public.pos_cart_items FOR INSERT WITH CHECK (is_org_member(organization_id)); CREATE POLICY "Tenant isolation update" ON public.pos_cart_items FOR UPDATE USING (is_org_member(organization_id)); CREATE POLICY "Tenant isolation delete" ON public.pos_cart_items FOR DELETE USING (is_org_member(organization_id)); CREATE INDEX idx_pos_cart_items_cart ON public.pos_cart_items(cart_id); ALTER TABLE public.invoices ADD COLUMN IF NOT EXISTS cashier_user_id uuid; ALTER TABLE public.invoices ADD COLUMN IF NOT EXISTS store_credit_applied_cents integer NOT NULL DEFAULT 0; ALTER TABLE public.invoices ADD COLUMN IF NOT EXISTS promotion_discount_cents integer NOT NULL DEFAULT 0; ALTER TABLE public.invoices ADD COLUMN IF NOT EXISTS promotion_id uuid; CREATE OR REPLACE FUNCTION public.decrement_product_stock(_product_id uuid, _quantity integer, _allow_negative boolean DEFAULT false) RETURNS void LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $func$ DECLARE _org uuid; _current integer; BEGIN SELECT organization_id, stock_quantity INTO _org, _current FROM public.retail_products WHERE id = _product_id; IF _org IS NULL THEN RAISE EXCEPTION 'Product not found'; END IF; IF NOT is_org_member(_org) THEN RAISE EXCEPTION 'Not authorized'; END IF; IF NOT _allow_negative AND (_current - _quantity) < 0 THEN RAISE EXCEPTION 'Insufficient stock'; END IF; UPDATE public.retail_products SET stock_quantity = stock_quantity - _quantity WHERE id = _product_id; END; $func$;